option.value:
:root {
  --tocu-bg: #f5f4ed;
  --tocu-surface: #faf9f5;
  --tocu-surface-strong: #ffffff;
  --tocu-ink: #141413;
  --tocu-muted: #5e5d59;
  --tocu-subtle: #87867f;
  --tocu-border: #f0eee6;
  --tocu-border-strong: #e8e6dc;
  --tocu-accent: #c96442;
  --tocu-accent-strong: #b85637;
  --tocu-shadow-whisper: 0 4px 24px rgba(20, 20, 19, 0.05);
  --tocu-shadow-ring: 0 0 0 1px #d1cfc5;
  --tocu-radius-sm: 8px;
  --tocu-radius-md: 10px;
  --tocu-radius-lg: 12px;
  --tocu-radius-round: 999px;
  --tocu-max-width: 1180px;
  --tocu-transition: 220ms cubic-bezier(0.22, 1, 0.36, 1);
}

html,
body {
  margin: 0;
  padding: 0;
  scroll-behavior: smooth;
}

body.tocu-body {
  min-height: 100vh;
  background:
    radial-gradient(80% 65% at 0% 0%, rgba(201, 100, 66, 0.08), transparent 62%),
    radial-gradient(90% 72% at 100% 0%, rgba(232, 230, 220, 0.85), transparent 70%),
    var(--tocu-bg);
  color: var(--tocu-ink);
  font-family: "Noto Sans SC", "PingFang SC", "Microsoft YaHei", sans-serif;
}

*,
*::before,
*::after {
  box-sizing: border-box;
}

a {
  color: inherit;
  text-decoration: none;
}

img {
  display: block;
  max-width: 100%;
}

button,
input,
select,
textarea {
  font: inherit;
}

code {
  font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace;
}

.sr-only {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border: 0;
}

.tocu-site-shell {
  width: min(1440px, calc(100% - 2rem));
  margin: 0 auto;
  padding: 1rem 0 3rem;
}

.tocu-site-shell--home {
  width: min(1500px, calc(100% - 2rem));
  padding-top: 0.35rem;
  padding-bottom: 0;
}

.tocu-flash-stack {
  display: grid;
  gap: 0.75rem;
  margin-bottom: 1rem;
}

.tocu-flash {
  border-radius: var(--tocu-radius-sm);
  border: 1px solid var(--tocu-border-strong);
  background: var(--tocu-surface);
  padding: 0.95rem 1rem;
  box-shadow: var(--tocu-shadow-whisper);
  font-size: 0.95rem;
}

.tocu-flash--success {
  border-color: rgba(22, 101, 52, 0.15);
  color: #166534;
}

.tocu-flash--error {
  border-color: rgba(185, 28, 28, 0.15);
  color: #b53333;
}

.tocu-site-header {
  position: sticky;
  top: 0;
  z-index: 40;
  border-bottom: 1px solid var(--tocu-border);
  background: rgba(245, 244, 237, 0.94);
  backdrop-filter: blur(14px);
}

.tocu-site-header__inner,
.tocu-mobile-nav,
.tocu-site-footer__inner {
  width: min(var(--tocu-max-width), calc(100% - 2rem));
  margin: 0 auto;
}

.tocu-site-header__inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 1rem;
  padding: 0.5rem 0;
}

.tocu-site-header__brand {
  display: inline-flex;
  flex-direction: column;
  gap: 0.1rem;
}

.tocu-site-header__mark,
.tocu-site-footer__brand {
  font-family: "Source Serif 4", "Noto Serif SC", serif;
  font-size: 1.7rem;
  font-weight: 600;
  line-height: 1;
  color: var(--tocu-ink);
}

.tocu-site-header__logo,
.tocu-site-footer__logo {
  height: 5rem;
  width: auto;
  object-fit: contain;
  line-height: 1;
}

.tocu-site-header__subtitle,
.tocu-site-footer__copy {
  font-size: 0.78rem;
  color: var(--tocu-subtle);
  letter-spacing: 0.08em;
  text-transform: uppercase;
}

.tocu-site-nav,
.tocu-site-header__actions,
.tocu-site-footer__links,
.tocu-home-cover__actions,
.tocu-home-links,
.tocu-directory-card__top,
.tocu-guide-main__heading,
.tocu-auth-modal__head,
.tocu-auth-modal__tabs,
.tocu-resume-card,
.tocu-breadcrumb {
  display: flex;
  align-items: center;
}

.tocu-site-nav {
  gap: 0.45rem;
  padding: 0.32rem;
  border: 1px solid var(--tocu-border);
  border-radius: var(--tocu-radius-md);
  background: rgba(250, 249, 245, 0.82);
}

.tocu-site-nav__link,
.tocu-mobile-nav__link {
  border-radius: var(--tocu-radius-sm);
  padding: 0.55rem 0.95rem;
  font-size: 0.92rem;
  color: var(--tocu-muted);
  transition: background-color var(--tocu-transition), color var(--tocu-transition), box-shadow var(--tocu-transition);
}

.tocu-site-nav__link:hover,
.tocu-mobile-nav__link:hover {
  color: var(--tocu-ink);
}

.tocu-site-nav__link.is-active,
.tocu-mobile-nav__link.is-active {
  background: #4F1C51;
  color: var(--tocu-surface);
  box-shadow: var(--tocu-shadow-ring);
}

.tocu-site-header__actions {
  gap: 0.75rem;
}

.tocu-mobile-nav {
  display: none;
  gap: 0.5rem;
  flex-wrap: wrap;
  overflow: visible;
  padding-bottom: 0.9rem;
}

.tocu-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 0.4rem;
  min-height: 44px;
  border-radius: var(--tocu-radius-md);
  padding: 0.8rem 1.2rem;
  border: 1px solid transparent;
  transition: transform var(--tocu-transition), background-color var(--tocu-transition), border-color var(--tocu-transition), color var(--tocu-transition), box-shadow var(--tocu-transition);
  cursor: pointer;
}

.tocu-btn:hover {
  transform: translateY(-1px);
}

.tocu-btn--primary {
  background: #A55B4B;
  color: var(--tocu-surface);
  box-shadow: 0 0 0 1px #A55B4B;
}

.tocu-btn--primary:hover {
  background: #944B3D;
}

.tocu-btn--secondary {
  background: var(--tocu-border-strong);
  color: #4d4c48;
  box-shadow: var(--tocu-shadow-ring);
}

.tocu-btn--secondary:hover {
  border-color: #c2c0b6;
}

.tocu-btn--dark {
  background: #210F37;
  color: var(--tocu-surface);
  box-shadow: 0 0 0 1px #210F37;
}

.tocu-btn--dark:hover {
  background: #1a0a2a;
}

.tocu-btn--ghost {
  background: var(--tocu-surface-strong);
  border-color: var(--tocu-border-strong);
  color: var(--tocu-ink);
  box-shadow: var(--tocu-shadow-ring);
}

.tocu-btn--small {
  min-height: 38px;
  padding: 0.6rem 1rem;
  font-size: 0.92rem;
}

.tocu-btn--full {
  width: 100%;
}

.tocu-user-menu {
  position: relative;
}

.tocu-user-menu__trigger {
  display: inline-flex;
  align-items: center;
  gap: 0.65rem;
  border: 1px solid var(--tocu-border);
  border-radius: var(--tocu-radius-md);
  background: var(--tocu-surface);
  padding: 0.35rem 0.4rem 0.35rem 0.85rem;
  color: var(--tocu-ink);
  cursor: pointer;
}

.tocu-user-menu__name {
  font-size: 0.92rem;
  color: var(--tocu-muted);
}

.tocu-user-menu__avatar {
  width: 2.25rem;
  height: 2.25rem;
  border-radius: var(--tocu-radius-round);
  display: grid;
  place-items: center;
  color: #fff;
  font-weight: 700;
}

.tocu-user-menu__panel {
  position: absolute;
  right: 0;
  top: calc(100% + 0.75rem);
  width: min(320px, 92vw);
  padding: 1rem;
  border-radius: var(--tocu-radius-lg);
  border: 1px solid var(--tocu-border);
  background: rgba(250, 249, 245, 0.98);
  box-shadow: 0 20px 40px rgba(20, 20, 19, 0.08);
  display: none;
}

.tocu-user-menu:hover .tocu-user-menu__panel,
.tocu-user-menu:focus-within .tocu-user-menu__panel {
  display: block;
}

.tocu-user-menu__eyebrow,
.tocu-page-hero__eyebrow,
.tocu-home-cover__eyebrow,
.tocu-home-links__eyebrow,
.tocu-guide-nav__eyebrow,
.tocu-guide-main__step,
.tocu-guide-side__eyebrow,
.tocu-resume-card__eyebrow,
.tocu-assistant-shell__intro-label,
.tocu-directory-card__badge,
.tocu-faq-card__badge {
  font-size: 0.73rem;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: var(--tocu-subtle);
}

.tocu-user-menu__title,
.tocu-auth-modal__title,
.tocu-guide-nav__title,
.tocu-guide-side__title,
.tocu-resume-card__title {
  margin: 0.15rem 0 0;
  font-family: "Source Serif 4", "Noto Serif SC", serif;
  font-size: 1.35rem;
  font-weight: 600;
  line-height: 1.2;
}

.tocu-user-menu__email,
.tocu-guide-nav__hint,
.tocu-guide-side__body,
.tocu-auth-modal__body {
  color: var(--tocu-muted);
  font-size: 0.92rem;
  line-height: 1.7;
}

.tocu-inline-form,
.tocu-form-stack {
  display: grid;
  gap: 0.9rem;
}

.tocu-form-stack {
  margin-top: 1rem;
}

.tocu-field {
  display: grid;
  gap: 0.45rem;
}

.tocu-field__label {
  font-size: 0.9rem;
  color: var(--tocu-muted);
}

.tocu-input {
  width: 100%;
  min-height: 46px;
  border-radius: var(--tocu-radius-md);
  border: 1px solid var(--tocu-border-strong);
  background: var(--tocu-surface-strong);
  color: var(--tocu-ink);
  padding: 0.8rem 0.95rem;
  transition: border-color var(--tocu-transition), box-shadow var(--tocu-transition);
}

.tocu-input:focus {
  outline: none;
  border-color: var(--tocu-focus, #3898ec);
  box-shadow: 0 0 0 3px rgba(56, 152, 236, 0.12);
}

.tocu-input--textarea {
  min-height: 120px;
  resize: vertical;
}

.tocu-page-stack {
  display: grid;
  gap: 1.4rem;
}

.tocu-page-hero,
.tocu-directory-toolbar,
.tocu-resume-card,
.tocu-guide-main__surface,
.tocu-guide-nav__panel,
.tocu-guide-side__panel,
.tocu-home-cover__inner,
.tocu-home-links__card,
.tocu-faq-card {
  border-radius: var(--tocu-radius-lg);
  border: 1px solid var(--tocu-border);
  background: rgba(250, 249, 245, 0.56);
  box-shadow: none;
}

.tocu-page-hero {
  border: 0;
  background: transparent;
  padding: 0 0 1rem;
}

.tocu-page-hero__title,
.tocu-home-cover__title,
.tocu-home-cover__slogan,
.tocu-directory-card__title,
.tocu-stage-card__title,
.tocu-faq-card__title,
.tocu-guide-main__title {
  font-family: "Source Serif 4", "Noto Serif SC", serif;
  font-weight: 600;
  color: var(--tocu-ink);
}

.tocu-page-hero__title {
  margin: 0.55rem 0 0;
  font-size: clamp(2.4rem, 5vw, 3.8rem);
  line-height: 1.12;
}

.tocu-page-hero__summary {
  max-width: 48rem;
  margin: 0.9rem 0 0;
  font-size: 1.02rem;
  line-height: 1.8;
  color: var(--tocu-muted);
}

.tocu-page-hero__badge {
  display: inline-flex;
  margin-top: 1rem;
  padding: 0.55rem 0.9rem;
  border-radius: var(--tocu-radius-sm);
  background: var(--tocu-border-strong);
  color: #4d4c48;
  font-size: 0.92rem;
}

.tocu-breadcrumb a {
  color: var(--tocu-muted);
  font-size: 0.95rem;
}

.tocu-home-cover {
  position: relative;
  display: grid;
  grid-template-columns: minmax(0, 1.08fr) minmax(380px, 0.92fr);
  gap: clamp(2rem, 5vw, 6rem);
  align-items: center;
  min-height: calc(100svh - 6.4rem);
  padding: clamp(0.9rem, 1.8vw, 1.8rem) clamp(0.75rem, 1.5vw, 1.4rem) clamp(1.25rem, 2vw, 1.9rem);
  overflow: hidden;
}

.tocu-home-cover__intro {
  display: grid;
  align-content: center;
  gap: 1.1rem;
  min-height: min(100%, 42rem);
  width: min(100%, 32rem);
  justify-self: center;
}

.tocu-home-cover__title {
  margin: 0;
  display: grid;
  gap: 0.15em;
  font-size: clamp(5rem, 10vw, 8.8rem);
  line-height: 0.82;
  letter-spacing: -0.065em;
  color: #4F1C51;
}

.tocu-home-cover__title span {
  display: block;
}

.tocu-home-cover__slogan {
  margin: 0;
  max-width: 26rem;
  font-size: clamp(1.02rem, 1.6vw, 1.28rem);
  line-height: 1.7;
  color: color-mix(in srgb, var(--tocu-ink) 64%, var(--tocu-muted) 36%);
  font-family: "Noto Sans SC", "Source Sans Pro", sans-serif;
  font-weight: 800;
}

.tocu-home-cover__aside {
  position: relative;
  display: grid;
  align-content: center;
  justify-items: stretch;
  min-height: min(100%, 34rem);
}

.tocu-home-cover__bg-logo {
  position: absolute;
  top: 0;
  right: 30rem;
  bottom: 0;
  width: auto;
  max-width: none;
  height: 100%;
  object-fit: contain;
  object-position: right bottom;
  opacity: 0.15;
  z-index: 0;
  padding-right: 1rem;
  padding-bottom: 2rem;


}

.tocu-home-links {
  width: min(100%, 35rem);
  margin: 0 0 0 -2rem;
  display: grid;
  gap: 0;
  border-radius: var(--tocu-radius-lg);
  border: 1px solid rgba(232, 230, 220, 0.88);
  background: linear-gradient(180deg, rgba(255, 252, 249, 0.82), rgba(255, 249, 244, 0.52));
  backdrop-filter: blur(10px);
  box-shadow: 0 18px 44px rgba(20, 20, 19, 0.06);
  overflow: hidden;
  position: relative;
  z-index: 1;
}

.tocu-home-links__card {
  position: relative;
  padding: 1.45rem 1.5rem;
  display: grid;
  gap: 0.4rem 0.9rem;
  grid-template-columns: minmax(0, 1fr) auto;
  grid-template-areas:
    "eyebrow arrow"
    "title arrow"
    "body arrow";
  align-items: start;
  border-radius: 0;
  border: 0;
  border-top: 1px solid rgba(232, 230, 220, 0.92);
  background: transparent;
  box-shadow: none;
  transition: transform var(--tocu-transition), color var(--tocu-transition), background-color var(--tocu-transition);
}

.tocu-home-links__card:first-child {
  border-top: 0;
}

.tocu-home-links__card:hover {
  transform: translateX(4px);
  background: rgba(255, 255, 255, 0.26);
}

.tocu-home-cover__watermark {
  position: fixed;
  right: 0;
  bottom: 0;
  margin: 0;
  font-family: "Noto Sans SC", "Source Sans Pro", sans-serif;
  font-size: clamp(5.2rem, 8.4vw, 7.8rem);
  font-weight: 1000;
  line-height: 0.88;
  letter-spacing: -0.08em;
  color: rgba(20, 20, 19, 0.055);
  white-space: nowrap;
  pointer-events: none;
  z-index: -1;
}

.tocu-stage-card:hover,
.tocu-directory-card:hover,
.tocu-faq-card:hover {
  transform: translateY(-2px);
  border-color: var(--tocu-border-strong);
}

.tocu-home-links__title,
.tocu-directory-card__title,
.tocu-stage-card__title,
.tocu-faq-card__title {
  font-size: 1.62rem;
  line-height: 1.14;
}

.tocu-home-links__title {
  grid-area: title;
  align-self: start;
}

.tocu-home-links__body,
.tocu-directory-card__school,
.tocu-stage-card__body,
.tocu-faq-card__body,
.tocu-resume-card__body {
  color: color-mix(in srgb, var(--tocu-ink) 72%, var(--tocu-muted) 28%);
  line-height: 1.68;
}

.tocu-home-links__body {
  grid-area: body;
  max-width: none;
  justify-self: start;
  align-self: start;
  font-size: 0.97rem;
  word-spacing: -0.05em;
}

.tocu-home-links__eyebrow {
  grid-area: eyebrow;
  color: color-mix(in srgb, var(--tocu-accent-strong) 70%, var(--tocu-subtle) 30%);
  align-self: start;
}

.tocu-home-links__arrow {
  grid-area: arrow;
  align-self: start;
  font-family: "Source Serif 4", "Noto Serif SC", serif;
  font-size: clamp(1.5rem, 2vw, 2rem);
  color: color-mix(in srgb, var(--tocu-ink) 46%, transparent);
}

.tocu-directory-toolbar {
  border: 0;
  background: transparent;
  padding: 0 0 0.85rem;
}

.tocu-directory-toolbar__filters {
  display: grid;
  grid-template-columns: minmax(0, 2.35fr) minmax(176px, 1fr);
  gap: 0.65rem;
  align-items: end;
  max-width: min(780px, 100%);
}

.tocu-field--search {
  margin: 0;
  min-width: 0;
}

.tocu-field--college {
  margin: 0;
  min-width: 0;
  max-width: none;
}

.tocu-field--college .tocu-field__label {
  margin-bottom: 0.25rem;
  font-size: 0.72rem;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: var(--tocu-subtle);
}

.tocu-directory-grid,
.tocu-stage-grid {
  display: grid;
  gap: 1rem;
}

.tocu-directory-grid {
  grid-template-columns: repeat(2, minmax(0, 1fr));
}

.tocu-directory-card {
  padding: 1.35rem;
  display: grid;
  gap: 1rem;
  border-radius: var(--tocu-radius-lg);
  border: 1px solid var(--tocu-border);
  background: rgba(255, 255, 255, 0.32);
  box-shadow: none;
  transition: transform var(--tocu-transition), border-color var(--tocu-transition), box-shadow var(--tocu-transition);
}

.tocu-directory-card__top {
  justify-content: space-between;
  align-items: start;
  gap: 1rem;
}

.tocu-program-title {
  display: flex;
  align-items: baseline;
  gap: 0.5rem;
  flex-wrap: wrap;
  margin: 0;
}

.tocu-program-title__en {
  font-family: "Noto Sans SC", "PingFang SC", "Microsoft YaHei", sans-serif;
  font-size: 0.9rem;
  font-weight: 500;
  color: var(--tocu-subtle);
}

.tocu-directory-card__school {
  margin: 0.35rem 0 0;
}

.tocu-directory-card__badge {
  color: var(--tocu-accent-strong);
  background: rgba(201, 100, 66, 0.08);
  border: 1px solid rgba(201, 100, 66, 0.16);
  border-radius: var(--tocu-radius-sm);
  padding: 0.45rem 0.7rem;
}

.tocu-directory-card__facts {
  display: grid;
  gap: 0.75rem;
  margin: 0;
}

.tocu-directory-card__facts div {
  display: grid;
  gap: 0.18rem;
}

.tocu-directory-card__facts dt {
  font-size: 0.78rem;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: var(--tocu-subtle);
}

.tocu-directory-card__facts dd {
  margin: 0;
  line-height: 1.7;
  color: var(--tocu-ink);
}

.tocu-directory-card__link,
.tocu-stage-card__cta {
  color: var(--tocu-accent-strong);
  font-weight: 600;
}

.tocu-resume-card {
  justify-content: space-between;
  gap: 1rem;
  padding: 1.2rem 1.35rem;
  background: rgba(255, 255, 255, 0.22);
}

.tocu-resume-card__title {
  margin-top: 0.4rem;
}

.tocu-stage-grid {
  grid-template-columns: repeat(3, minmax(0, 1fr));
}

.tocu-stage-card {
  padding: 1.35rem;
  border-radius: var(--tocu-radius-lg);
  border: 1px solid var(--tocu-border);
  background: rgba(255, 255, 255, 0.28);
  box-shadow: none;
  display: grid;
  gap: 0.9rem;
  transition: transform var(--tocu-transition), border-color var(--tocu-transition), box-shadow var(--tocu-transition);
}

.tocu-stage-card.is-highlighted {
  border-color: rgba(201, 100, 66, 0.26);
  background: rgba(255, 247, 243, 0.95);
  box-shadow: 0 0 0 1px rgba(201, 100, 66, 0.16);
}

.tocu-stage-card__meta {
  display: flex;
  justify-content: space-between;
  gap: 1rem;
  align-items: center;
  flex-wrap: wrap;
}

.tocu-stage-card__index {
  font-size: 0.75rem;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: var(--tocu-subtle);
}

.tocu-stage-card__range {
  font-size: 0.86rem;
  color: var(--tocu-accent-strong);
}

.tocu-guide-layout {
  display: grid;
  grid-template-columns: 250px minmax(0, 1fr) 260px;
  gap: 1rem;
  align-items: start;
}

.tocu-guide-nav,
.tocu-guide-side {
  position: sticky;
  top: 6.25rem;
}

.tocu-guide-nav__panel,
.tocu-guide-side__panel,
.tocu-guide-main__surface,
.tocu-faq-card,
.tocu-auth-modal {
  padding: 1.25rem;
}

.tocu-guide-nav__list,
.tocu-guide-side__materials,
.tocu-guide-main__section ol,
.tocu-guide-main__section ul {
  margin: 0;
  padding-left: 1.15rem;
}

.tocu-guide-nav__list {
  list-style: none;
  padding-left: 0;
  display: grid;
  gap: 0.55rem;
  margin-top: 1rem;
}

.tocu-guide-nav__link {
  display: flex;
  gap: 0.55rem;
  align-items: center;
  padding: 0.8rem 0.9rem;
  border-radius: var(--tocu-radius-md);
  border: 1px solid var(--tocu-border);
  color: var(--tocu-muted);
  transition: background-color var(--tocu-transition), color var(--tocu-transition), border-color var(--tocu-transition);
}

.tocu-guide-nav__link:hover {
  border-color: var(--tocu-border-strong);
  color: var(--tocu-ink);
}

.tocu-guide-nav__link.is-current {
  background: var(--tocu-ink);
  color: var(--tocu-surface);
  border-color: var(--tocu-ink);
}

.tocu-guide-main {
  display: grid;
  gap: 1rem;
}

.tocu-guide-main__heading {
  justify-content: space-between;
  gap: 1rem;
  align-items: start;
}

.tocu-guide-main__title {
  margin: 0.35rem 0 0;
  font-size: clamp(1.8rem, 3vw, 2.4rem);
  line-height: 1.18;
}

.tocu-guide-main__image {
  margin-top: 1.2rem;
  border-radius: var(--tocu-radius-lg);
  border: 1px solid var(--tocu-border);
  aspect-ratio: 16 / 9;
  object-fit: cover;
  background: var(--tocu-border-strong);
}

.tocu-guide-main__section {
  margin-top: 1.4rem;
}

.tocu-guide-main__section h3,
.tocu-guide-comments__title {
  margin: 0;
  font-family: "Source Serif 4", "Noto Serif SC", serif;
  font-size: 1.4rem;
  line-height: 1.2;
}

.tocu-guide-main__section ol,
.tocu-guide-main__section ul {
  margin-top: 0.9rem;
  color: var(--tocu-muted);
  line-height: 1.85;
}

.tocu-complete-button {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-height: 44px;
  padding: 0.75rem 1rem;
  border: 0;
  border-radius: var(--tocu-radius-md);
  color: #fff;
  cursor: pointer;
  transition: transform var(--tocu-transition), opacity var(--tocu-transition);
}

.tocu-complete-button:hover {
  transform: translateY(-1px);
}

.tocu-guide-comments {
  margin-top: 1rem;
  display: grid;
  gap: 0.85rem;
}

.tocu-callout {
  margin-top: 0.8rem;
  border-radius: var(--tocu-radius-md);
  border: 1px solid rgba(201, 100, 66, 0.18);
  background: rgba(255, 247, 243, 0.92);
  color: var(--tocu-muted);
  padding: 0.95rem 1rem;
}

.tocu-callout a {
  color: var(--tocu-accent-strong);
}

.tocu-guide-side {
  display: grid;
  gap: 1rem;
}

.tocu-guide-side__panel--accent {
  background: linear-gradient(180deg, rgba(255, 247, 243, 0.98), rgba(250, 249, 245, 0.96));
  border-color: rgba(201, 100, 66, 0.18);
}

.tocu-guide-side__materials {
  margin-top: 0.9rem;
  display: grid;
  gap: 0.7rem;
  list-style: none;
  padding-left: 0;
}

.tocu-guide-side__materials li {
  padding: 0.8rem 0.9rem;
  border-radius: var(--tocu-radius-md);
  border: 1px solid var(--tocu-border);
  background: rgba(255, 255, 255, 0.7);
  color: var(--tocu-muted);
  line-height: 1.65;
}

.tocu-site-shell--assistant {
  width: min(1500px, calc(100% - 2rem));
  padding-top: 0.55rem;
  padding-bottom: 1.25rem;
}

body.tocu-body--assistant {
  background:
    radial-gradient(82% 70% at 50% 0%, rgba(201, 100, 66, 0.06), transparent 72%),
    radial-gradient(70% 55% at 0% 8%, rgba(255, 255, 255, 0.7), transparent 68%),
    var(--tocu-bg);
}

.tocu-site-header--assistant {
  border-bottom-color: rgba(232, 230, 220, 0.6);
  background: rgba(245, 244, 237, 0.76);
  backdrop-filter: blur(18px);
}

.tocu-site-header--assistant .tocu-site-nav {
  background: rgba(250, 249, 245, 0.64);
  border-color: rgba(232, 230, 220, 0.74);
  box-shadow: none;
}

.tocu-site-header--assistant .tocu-site-header__subtitle {
  color: color-mix(in srgb, var(--tocu-subtle) 82%, transparent);
}

.tocu-assistant-shell {
  position: relative;
  display: grid;
  min-height: calc(100svh - 7.4rem);
}

.tocu-assistant-shell__window {
  width: min(1240px, 100%);
  min-height: 100%;
  margin: 0 auto;
  display: grid;
  align-content: start;
  padding: clamp(1rem, 3vw, 2rem) clamp(0.2rem, 1vw, 0.4rem);
}

.tocu-assistant-shell__intro {
  width: min(1040px, 100%);
  margin: 0 auto;
  display: grid;
  justify-items: center;
  text-align: center;
  gap: 1.35rem;
  transition: opacity var(--tocu-transition), transform var(--tocu-transition), max-height var(--tocu-transition), margin var(--tocu-transition);
}

.tocu-assistant-shell__headline {
  margin: 0;
  font-family: "Source Serif 4", "Noto Serif SC", serif;
  font-size: clamp(2.9rem, 5vw, 4.5rem);
  font-weight: 600;
  line-height: 1.06;
  letter-spacing: -0.04em;
  color: var(--tocu-ink);
}

.tocu-assistant-shell__intro-copy {
  max-width: 34rem;
  margin: 0;
  font-size: 1rem;
  line-height: 1.8;
  color: var(--tocu-muted);
}

.tocu-chip-list {
  display: flex;
  flex-wrap: wrap;
  gap: 0.65rem;
}

.tocu-chip-list--assistant {
  justify-content: center;
  gap: 0.8rem 0.9rem;
  max-width: 92rem;
}

.tocu-chip {
  border: 1px solid rgba(232, 230, 220, 0.96);
  border-radius: var(--tocu-radius-md);
  background: rgba(255, 255, 255, 0.56);
  color: color-mix(in srgb, var(--tocu-ink) 82%, var(--tocu-muted) 18%);
  padding: 0.8rem 1.25rem;
  font-size: 1rem;
  line-height: 1.45;
  transition: border-color var(--tocu-transition), color var(--tocu-transition), background-color var(--tocu-transition), transform var(--tocu-transition);
  cursor: pointer;
}

.tocu-chip:hover {
  transform: translateY(-1px);
  border-color: rgba(201, 100, 66, 0.24);
  color: var(--tocu-ink);
  background: rgba(255, 255, 255, 0.76);
}

.tocu-chat-surface {
  width: min(940px, 100%);
  margin: 0 auto;
  max-height: 0;
  overflow: hidden;
  opacity: 0;
  pointer-events: none;
  transform: translateY(1.5rem);
  transition: opacity var(--tocu-transition), transform var(--tocu-transition);
}

.tocu-chat-log {
  min-height: calc(100svh - 16.5rem);
  max-height: calc(100svh - 16.5rem);
  overflow-y: auto;
  padding: 0 0 0.75rem;
  display: grid;
  gap: 1rem;
  background: transparent;
}

.tocu-chat-message {
  display: flex;
}

.tocu-chat-message--assistant {
  justify-content: flex-start;
}

.tocu-chat-message--user {
  justify-content: flex-end;
}

.tocu-chat-bubble {
  max-width: min(80%, 42rem);
  padding: 0.95rem 1.1rem;
  border-radius: var(--tocu-radius-lg);
  font-size: 0.98rem;
  line-height: 1.8;
  box-shadow: 0 10px 24px rgba(20, 20, 19, 0.04);
}

.tocu-chat-bubble--assistant {
  border: 1px solid rgba(232, 230, 220, 0.96);
  border-bottom-left-radius: 0.55rem;
  background: rgba(255, 255, 255, 0.84);
  color: var(--tocu-ink);
}

.tocu-chat-bubble--user {
  border-bottom-right-radius: 0.55rem;
  background: var(--tocu-accent);
  color: var(--tocu-surface);
}

.tocu-chat-bubble__text {
  margin: 0;
  white-space: pre-wrap;
}

.tocu-chat-bubble__meta-title,
.tocu-chat-bubble__timing {
  margin: 0.7rem 0 0;
  font-size: 0.74rem;
  color: color-mix(in srgb, var(--tocu-ink) 60%, var(--tocu-subtle) 40%);
}

.tocu-chat-bubble__sources {
  margin: 0.45rem 0 0;
  padding-left: 1rem;
  display: grid;
  gap: 0.2rem;
}

.tocu-chat-bubble__sources a {
  color: var(--tocu-accent-strong);
  font-size: 0.8rem;
}

.tocu-chat-bubble__sources a:hover {
  color: var(--tocu-accent);
}

.tocu-chat-compose {
  width: min(940px, calc(100% - 1rem));
}

.tocu-chat-compose--fixed {
  position: fixed;
  left: 50%;
  bottom: calc(1.1rem + env(safe-area-inset-bottom));
  transform: translateX(-50%);
  z-index: 32;
}

.tocu-chat-compose__status {
  margin: 0 0 0.45rem 0.3rem;
  color: var(--tocu-muted);
  font-size: 0.9rem;
}

.tocu-chat-compose__form {
  margin: 0;
}

.tocu-chat-compose__surface {
  display: grid;
  grid-template-columns: minmax(0, 1fr) auto;
  gap: 0.85rem;
  align-items: end;
  padding: 0.7rem 0.75rem 0.75rem 1.05rem;
  border-radius: var(--tocu-radius-lg);
  border: 1px solid rgba(196, 202, 255, 0.95);
  background: rgba(250, 249, 245, 0.98);
  box-shadow: 0 14px 36px rgba(146, 174, 255, 0.16);
}

.tocu-chat-compose__input {
  width: 100%;
  min-height: 4.8rem;
  max-height: 12rem;
  border: 0;
  background: transparent;
  color: var(--tocu-ink);
  resize: none;
  padding: 0.45rem 0 0;
  line-height: 1.7;
}

.tocu-chat-compose__input::placeholder {
  color: color-mix(in srgb, var(--tocu-subtle) 70%, transparent);
}

.tocu-chat-compose__input:focus {
  outline: none;
}

.tocu-chat-compose__send {
  width: 3.1rem;
  height: 3.1rem;
  border: 0;
  border-radius: var(--tocu-radius-round);
  display: grid;
  place-items: center;
  background: rgba(20, 20, 19, 0.08);
  color: var(--tocu-ink);
  font-size: 1.35rem;
  line-height: 1;
  cursor: pointer;
  transition: transform var(--tocu-transition), background-color var(--tocu-transition), color var(--tocu-transition);
}

.tocu-chat-compose__send:hover {
  transform: translateY(-1px);
  background: var(--tocu-accent);
  color: var(--tocu-surface);
}

.tocu-chat-compose__send:disabled {
  opacity: 0.72;
  cursor: not-allowed;
  transform: none;
}

.tocu-assistant-shell[data-assistant-stage="chat"] .tocu-assistant-shell__window {
  align-content: start;
}

.tocu-assistant-shell[data-assistant-stage="chat"] .tocu-assistant-shell__intro {
  opacity: 0;
  transform: translateY(-1.25rem);
  pointer-events: none;
  max-height: 0;
  overflow: hidden;
  margin-bottom: -1rem;
}

.tocu-assistant-shell[data-assistant-stage="chat"] .tocu-chat-surface {
  max-height: none;
  overflow: visible;
  opacity: 1;
  pointer-events: auto;
  transform: translateY(0);
}

.tocu-faq-list {
  display: grid;
  gap: 1rem;
}

.tocu-faq-card {
  display: grid;
  gap: 0.8rem;
}

.tocu-faq-card__badge {
  color: var(--tocu-accent-strong);
}

.tocu-auth-modal {
  width: min(560px, 100%);
  border-radius: var(--tocu-radius-lg);
  border: 1px solid var(--tocu-border);
  background: rgba(250, 249, 245, 0.98);
  box-shadow: 0 24px 44px rgba(20, 20, 19, 0.12);
}

.tocu-auth-modal__head {
  justify-content: space-between;
  gap: 1rem;
}

.tocu-auth-modal__tabs {
  gap: 0.5rem;
  margin-top: 1rem;
}

.tocu-auth-modal__tab {
  border-radius: var(--tocu-radius-sm);
  padding: 0.65rem 1rem;
}

.tocu-site-footer {
  border-top: 1px solid var(--tocu-border);
  margin-top: 2rem;
  padding: 1.4rem 0 2.5rem;
}

.tocu-site-footer__inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 1rem;
}

.tocu-site-footer__links {
  gap: 1rem;
  flex-wrap: wrap;
}

.tocu-site-footer__links a {
  color: var(--tocu-muted);
  font-size: 0.95rem;
}

.tocu-site-footer__links a:hover,
.tocu-breadcrumb a:hover {
  color: var(--tocu-ink);
}

/* 专业速查优化搜索栏样式 */
.tocu-optimized-searchbar {
  min-height: 4rem;
  width: 100%;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 1.5rem 0.5rem 1.5rem 0.5rem;
}
.tocu-optimized-searchbar__inner {
  width: 100%;
  max-width: 900px;
  display: flex;
  flex-direction: column;
  gap: 1rem;
}
@media (min-width: 640px) {
  .tocu-optimized-searchbar__inner {
    flex-direction: row;
    align-items: center;
  }
}
.tocu-optimized-searchbar__input-wrap {
  position: relative;
  flex: 1 1 0%;
  width: 100%;
}
.tocu-optimized-searchbar__icon {
  position: absolute;
  left: 0.75rem;
  top: 0;
  bottom: 0;
  display: flex;
  align-items: center;
  color: #bdbdbd;
  pointer-events: none;
}
.tocu-optimized-searchbar__input {
  width: 100%;
  padding-left: 2.5rem;
  padding-right: 2.5rem;
  padding-top: 0.85rem;
  padding-bottom: 0.85rem;
  background: #fff;
  border: 1px solid #e5e7eb;
  border-radius: 0.75rem;
  font-size: 1rem;
  transition: box-shadow 0.2s, border-color 0.2s;
  box-shadow: 0 1px 4px rgba(20,20,19,0.04);
}
.tocu-optimized-searchbar__input:focus {
  outline: none;
  border-color: #210F37;
  box-shadow: 0 0 0 2px #210F3733;
}
.tocu-optimized-searchbar__clear {
  position: absolute;
  right: 0.75rem;
  top: 0;
  bottom: 0;
  display: flex;
  align-items: center;
  background: none;
  border: none;
  color: #bdbdbd;
  cursor: pointer;
  padding: 0;
  transition: color 0.2s;
}
.tocu-optimized-searchbar__clear:hover {
  color: #666;
}
.tocu-optimized-searchbar__select-wrap {
  position: relative;
  width: 100%;
  max-width: 12rem;
  min-width: 8rem;
}
.tocu-optimized-searchbar__select {
  width: 100%;
  padding-left: 1.2rem;
  padding-right: 2.5rem;
  padding-top: 0.85rem;
  padding-bottom: 0.85rem;
  background: #fff;
  border: 1px solid #e5e7eb;
  border-radius: 0.75rem;
  font-size: 1rem;
  color: #444;
  appearance: none;
  box-shadow: 0 1px 4px rgba(20,20,19,0.04);
  cursor: pointer;
  transition: box-shadow 0.2s, border-color 0.2s;
}
.tocu-optimized-searchbar__select:focus {
  outline: none;
  border-color: #210F37;
  box-shadow: 0 0 0 2px #210F3733;
}
.tocu-optimized-searchbar__chevron {
  position: absolute;
  right: 0.75rem;
  top: 0;
  bottom: 0;
  display: flex;
  align-items: center;
  color: #bdbdbd;
  pointer-events: none;
}
.tocu-optimized-searchbar__btn {
  width: 100%;
  max-width: 8rem;
  padding: 0.85rem 2.5rem;
  background: #210F37;
  color: #fff;
  font-size: 1rem;
  font-weight: 500;
  border: none;
  border-radius: 0.75rem;
  box-shadow: 0 1px 4px rgba(20,20,19,0.04);
  cursor: pointer;
  transition: background 0.2s;
  white-space: nowrap;
}
.tocu-optimized-searchbar__btn:hover, .tocu-optimized-searchbar__btn:focus {
  background: #1a0a2a;
}
@media (min-width: 640px) {
  .tocu-optimized-searchbar__btn {
    width: auto;
  }
}

:root {
  --tocu-bg: #f5f4ed;
  --tocu-surface: #faf9f5;
  --tocu-surface-strong: #ffffff;
  --tocu-ink: #141413;
  --tocu-muted: #5e5d59;
  --tocu-subtle: #87867f;
  --tocu-border: #f0eee6;
  --tocu-border-strong: #e8e6dc;
  --tocu-accent: #c96442;
  --tocu-accent-strong: #b85637;
  --tocu-shadow-whisper: 0 4px 24px rgba(20, 20, 19, 0.05);
  --tocu-shadow-ring: 0 0 0 1px #d1cfc5;
  --tocu-radius-sm: 8px;
  --tocu-radius-md: 10px;
  --tocu-radius-lg: 12px;
  --tocu-radius-round: 999px;
  --tocu-max-width: 1180px;
  --tocu-transition: 220ms cubic-bezier(0.22, 1, 0.36, 1);
}

html,
body {
  margin: 0;
  padding: 0;
  scroll-behavior: smooth;
}

body.tocu-body {
  min-height: 100vh;
  background:
    radial-gradient(80% 65% at 0% 0%, rgba(201, 100, 66, 0.08), transparent 62%),
    radial-gradient(90% 72% at 100% 0%, rgba(232, 230, 220, 0.85), transparent 70%),
    var(--tocu-bg);
  color: var(--tocu-ink);
  font-family: "Noto Sans SC", "PingFang SC", "Microsoft YaHei", sans-serif;
}

*,
*::before,
*::after {
  box-sizing: border-box;
}

a {
  color: inherit;
  text-decoration: none;
}

img {
  display: block;
  max-width: 100%;
}

button,
input,
select,
textarea {
  font: inherit;
}

code {
  font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace;
}

.sr-only {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border: 0;
}

.tocu-site-shell {
  width: min(1440px, calc(100% - 2rem));
  margin: 0 auto;
  padding: 1rem 0 3rem;
}

.tocu-site-shell--home {
  width: min(1500px, calc(100% - 2rem));
  padding-top: 0.35rem;
  padding-bottom: 0;
}

.tocu-flash-stack {
  display: grid;
  gap: 0.75rem;
  margin-bottom: 1rem;
}

.tocu-flash {
  border-radius: var(--tocu-radius-sm);
  border: 1px solid var(--tocu-border-strong);
  background: var(--tocu-surface);
  padding: 0.95rem 1rem;
  box-shadow: var(--tocu-shadow-whisper);
  font-size: 0.95rem;
}

.tocu-flash--success {
  border-color: rgba(22, 101, 52, 0.15);
  color: #166534;
}

.tocu-flash--error {
  border-color: rgba(185, 28, 28, 0.15);
  color: #b53333;
}

.tocu-site-header {
  position: sticky;
  top: 0;
  z-index: 40;
  border-bottom: 1px solid var(--tocu-border);
  background: rgba(245, 244, 237, 0.94);
  backdrop-filter: blur(14px);
}

.tocu-site-header__inner,
.tocu-mobile-nav,
.tocu-site-footer__inner {
  width: min(var(--tocu-max-width), calc(100% - 2rem));
  margin: 0 auto;
}

.tocu-site-header__inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 1rem;
  padding: 0.5rem 0;
}

.tocu-site-header__brand {
  display: inline-flex;
  flex-direction: column;
  gap: 0.1rem;
}

.tocu-site-header__mark,
.tocu-site-footer__brand {
  font-family: "Source Serif 4", "Noto Serif SC", serif;
  font-size: 1.7rem;
  font-weight: 600;
  line-height: 1;
  color: var(--tocu-ink);
}

.tocu-site-header__logo,
.tocu-site-footer__logo {
  height: 5rem;
  width: auto;
  object-fit: contain;
  line-height: 1;
}

.tocu-site-header__subtitle,
.tocu-site-footer__copy {
  font-size: 0.78rem;
  color: var(--tocu-subtle);
  letter-spacing: 0.08em;
  text-transform: uppercase;
}

.tocu-site-nav,
.tocu-site-header__actions,
.tocu-site-footer__links,
.tocu-home-cover__actions,
.tocu-home-links,
.tocu-directory-card__top,
.tocu-guide-main__heading,
.tocu-auth-modal__head,
.tocu-auth-modal__tabs,
.tocu-resume-card,
.tocu-breadcrumb {
  display: flex;
  align-items: center;
}

.tocu-site-nav {
  gap: 0.45rem;
  padding: 0.32rem;
  border: 1px solid var(--tocu-border);
  border-radius: var(--tocu-radius-md);
  background: rgba(250, 249, 245, 0.82);
}

.tocu-site-nav__link,
.tocu-mobile-nav__link {
  border-radius: var(--tocu-radius-sm);
  padding: 0.55rem 0.95rem;
  font-size: 0.92rem;
  color: var(--tocu-muted);
  transition: background-color var(--tocu-transition), color var(--tocu-transition), box-shadow var(--tocu-transition);
}

.tocu-site-nav__link:hover,
.tocu-mobile-nav__link:hover {
  color: var(--tocu-ink);
}

.tocu-site-nav__link.is-active,
.tocu-mobile-nav__link.is-active {
  background: #4F1C51;
  color: var(--tocu-surface);
  box-shadow: var(--tocu-shadow-ring);
}

.tocu-site-header__actions {
  gap: 0.75rem;
}

.tocu-mobile-nav {
  display: none;
  gap: 0.5rem;
  flex-wrap: wrap;
  overflow: visible;
  padding-bottom: 0.9rem;
}

.tocu-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 0.4rem;
  min-height: 44px;
  border-radius: var(--tocu-radius-md);
  padding: 0.8rem 1.2rem;
  border: 1px solid transparent;
  transition: transform var(--tocu-transition), background-color var(--tocu-transition), border-color var(--tocu-transition), color var(--tocu-transition), box-shadow var(--tocu-transition);
  cursor: pointer;
}

.tocu-btn:hover {
  transform: translateY(-1px);
}

.tocu-btn--primary {
  background: #A55B4B;
  color: var(--tocu-surface);
  box-shadow: 0 0 0 1px #A55B4B;
}

.tocu-btn--primary:hover {
  background: #944B3D;
}

.tocu-btn--secondary {
  background: var(--tocu-border-strong);
  color: #4d4c48;
  box-shadow: var(--tocu-shadow-ring);
}

.tocu-btn--secondary:hover {
  border-color: #c2c0b6;
}

.tocu-btn--dark {
  background: #210F37;
  color: var(--tocu-surface);
  box-shadow: 0 0 0 1px #210F37;
}

.tocu-btn--dark:hover {
  background: #1a0a2a;
}

.tocu-btn--ghost {
  background: var(--tocu-surface-strong);
  border-color: var(--tocu-border-strong);
  color: var(--tocu-ink);
  box-shadow: var(--tocu-shadow-ring);
}

.tocu-btn--small {
  min-height: 38px;
  padding: 0.6rem 1rem;
  font-size: 0.92rem;
}

.tocu-btn--full {
  width: 100%;
}

.tocu-user-menu {
  position: relative;
}

.tocu-user-menu__trigger {
  display: inline-flex;
  align-items: center;
  gap: 0.65rem;
  border: 1px solid var(--tocu-border);
  border-radius: var(--tocu-radius-md);
  background: var(--tocu-surface);
  padding: 0.35rem 0.4rem 0.35rem 0.85rem;
  color: var(--tocu-ink);
  cursor: pointer;
}

.tocu-user-menu__name {
  font-size: 0.92rem;
  color: var(--tocu-muted);
}

.tocu-user-menu__avatar {
  width: 2.25rem;
  height: 2.25rem;
  border-radius: var(--tocu-radius-round);
  display: grid;
  place-items: center;
  color: #fff;
  font-weight: 700;
}

.tocu-user-menu__panel {
  position: absolute;
  right: 0;
  top: calc(100% + 0.75rem);
  width: min(320px, 92vw);
  padding: 1rem;
  border-radius: var(--tocu-radius-lg);
  border: 1px solid var(--tocu-border);
  background: rgba(250, 249, 245, 0.98);
  box-shadow: 0 20px 40px rgba(20, 20, 19, 0.08);
  display: none;
}

.tocu-user-menu:hover .tocu-user-menu__panel,
.tocu-user-menu:focus-within .tocu-user-menu__panel {
  display: block;
}

.tocu-user-menu__eyebrow,
.tocu-page-hero__eyebrow,
.tocu-home-cover__eyebrow,
.tocu-home-links__eyebrow,
.tocu-guide-nav__eyebrow,
.tocu-guide-main__step,
.tocu-guide-side__eyebrow,
.tocu-resume-card__eyebrow,
.tocu-assistant-shell__intro-label,
.tocu-directory-card__badge,
.tocu-faq-card__badge {
  font-size: 0.73rem;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: var(--tocu-subtle);
}

.tocu-user-menu__title,
.tocu-auth-modal__title,
.tocu-guide-nav__title,
.tocu-guide-side__title,
.tocu-resume-card__title {
  margin: 0.15rem 0 0;
  font-family: "Source Serif 4", "Noto Serif SC", serif;
  font-size: 1.35rem;
  font-weight: 600;
  line-height: 1.2;
}

.tocu-user-menu__email,
.tocu-guide-nav__hint,
.tocu-guide-side__body,
.tocu-auth-modal__body {
  color: var(--tocu-muted);
  font-size: 0.92rem;
  line-height: 1.7;
}

.tocu-inline-form,
.tocu-form-stack {
  display: grid;
  gap: 0.9rem;
}

.tocu-form-stack {
  margin-top: 1rem;
}

.tocu-field {
  display: grid;
  gap: 0.45rem;
}

.tocu-field__label {
  font-size: 0.9rem;
  color: var(--tocu-muted);
}

.tocu-input {
  width: 100%;
  min-height: 46px;
  border-radius: var(--tocu-radius-md);
  border: 1px solid var(--tocu-border-strong);
  background: var(--tocu-surface-strong);
  color: var(--tocu-ink);
  padding: 0.8rem 0.95rem;
  transition: border-color var(--tocu-transition), box-shadow var(--tocu-transition);
}

.tocu-input:focus {
  outline: none;
  border-color: var(--tocu-focus, #3898ec);
  box-shadow: 0 0 0 3px rgba(56, 152, 236, 0.12);
}

.tocu-input--textarea {
  min-height: 120px;
  resize: vertical;
}

.tocu-page-stack {
  display: grid;
  gap: 1.4rem;
}

.tocu-page-hero,
.tocu-directory-toolbar,
.tocu-resume-card,
.tocu-guide-main__surface,
.tocu-guide-nav__panel,
.tocu-guide-side__panel,
.tocu-home-cover__inner,
.tocu-home-links__card,
.tocu-faq-card {
  border-radius: var(--tocu-radius-lg);
  border: 1px solid var(--tocu-border);
  background: rgba(250, 249, 245, 0.56);
  box-shadow: none;
}

.tocu-page-hero {
  border: 0;
  background: transparent;
  padding: 0 0 1rem;
}

.tocu-page-hero__title,
.tocu-home-cover__title,
.tocu-home-cover__slogan,
.tocu-directory-card__title,
.tocu-stage-card__title,
.tocu-faq-card__title,
.tocu-guide-main__title {
  font-family: "Source Serif 4", "Noto Serif SC", serif;
  font-weight: 600;
  color: var(--tocu-ink);
}

.tocu-page-hero__title {
  margin: 0.55rem 0 0;
  font-size: clamp(2.4rem, 5vw, 3.8rem);
  line-height: 1.12;
}

.tocu-page-hero__summary {
  max-width: 48rem;
  margin: 0.9rem 0 0;
  font-size: 1.02rem;
  line-height: 1.8;
  color: var(--tocu-muted);
}

.tocu-page-hero__badge {
  display: inline-flex;
  margin-top: 1rem;
  padding: 0.55rem 0.9rem;
  border-radius: var(--tocu-radius-sm);
  background: var(--tocu-border-strong);
  color: #4d4c48;
  font-size: 0.92rem;
}

.tocu-breadcrumb a {
  color: var(--tocu-muted);
  font-size: 0.95rem;
}

.tocu-home-cover {
  position: relative;
  display: grid;
  grid-template-columns: minmax(0, 1.08fr) minmax(380px, 0.92fr);
  gap: clamp(2rem, 5vw, 6rem);
  align-items: center;
  min-height: calc(100svh - 6.4rem);
  padding: clamp(0.9rem, 1.8vw, 1.8rem) clamp(0.75rem, 1.5vw, 1.4rem) clamp(1.25rem, 2vw, 1.9rem);
  overflow: hidden;
}

.tocu-home-cover__intro {
  display: grid;
  align-content: center;
  gap: 1.1rem;
  min-height: min(100%, 42rem);
  width: min(100%, 32rem);
  justify-self: center;
}

.tocu-home-cover__title {
  margin: 0;
  display: grid;
  gap: 0.15em;
  font-size: clamp(5rem, 10vw, 8.8rem);
  line-height: 0.82;
  letter-spacing: -0.065em;
  color: #4F1C51;
}

.tocu-home-cover__title span {
  display: block;
}

.tocu-home-cover__slogan {
  margin: 0;
  max-width: 26rem;
  font-size: clamp(1.02rem, 1.6vw, 1.28rem);
  line-height: 1.7;
  color: color-mix(in srgb, var(--tocu-ink) 64%, var(--tocu-muted) 36%);
  font-family: "Noto Sans SC", "Source Sans Pro", sans-serif;
  font-weight: 800;
}

.tocu-home-cover__aside {
  position: relative;
  display: grid;
  align-content: center;
  justify-items: stretch;
  min-height: min(100%, 34rem);
}

.tocu-home-cover__bg-logo {
  position: absolute;
  top: 0;
  right: 30rem;
  bottom: 0;
  width: auto;
  max-width: none;
  height: 100%;
  object-fit: contain;
  object-position: right bottom;
  opacity: 0.15;
  z-index: 0;
  padding-right: 1rem;
  padding-bottom: 2rem;


}

.tocu-home-links {
  width: min(100%, 35rem);
  margin: 0 0 0 -2rem;
  display: grid;
  gap: 0;
  border-radius: var(--tocu-radius-lg);
  border: 1px solid rgba(232, 230, 220, 0.88);
  background: linear-gradient(180deg, rgba(255, 252, 249, 0.82), rgba(255, 249, 244, 0.52));
  backdrop-filter: blur(10px);
  box-shadow: 0 18px 44px rgba(20, 20, 19, 0.06);
  overflow: hidden;
  position: relative;
  z-index: 1;
}

.tocu-home-links__card {
  position: relative;
  padding: 1.45rem 1.5rem;
  display: grid;
  gap: 0.4rem 0.9rem;
  grid-template-columns: minmax(0, 1fr) auto;
  grid-template-areas:
    "eyebrow arrow"
    "title arrow"
    "body arrow";
  align-items: start;
  border-radius: 0;
  border: 0;
  border-top: 1px solid rgba(232, 230, 220, 0.92);
  background: transparent;
  box-shadow: none;
  transition: transform var(--tocu-transition), color var(--tocu-transition), background-color var(--tocu-transition);
}

.tocu-home-links__card:first-child {
  border-top: 0;
}

.tocu-home-links__card:hover {
  transform: translateX(4px);
  background: rgba(255, 255, 255, 0.26);
}

.tocu-home-cover__watermark {
  position: fixed;
  right: 0;
  bottom: 0;
  margin: 0;
  font-family: "Noto Sans SC", "Source Sans Pro", sans-serif;
  font-size: clamp(5.2rem, 8.4vw, 7.8rem);
  font-weight: 1000;
  line-height: 0.88;
  letter-spacing: -0.08em;
  color: rgba(20, 20, 19, 0.055);
  white-space: nowrap;
  pointer-events: none;
  z-index: -1;
}

.tocu-stage-card:hover,
.tocu-directory-card:hover,
.tocu-faq-card:hover {
  transform: translateY(-2px);
  border-color: var(--tocu-border-strong);
}

.tocu-home-links__title,
.tocu-directory-card__title,
.tocu-stage-card__title,
.tocu-faq-card__title {
  font-size: 1.62rem;
  line-height: 1.14;
}

.tocu-home-links__title {
  grid-area: title;
  align-self: start;
}

.tocu-home-links__body,
.tocu-directory-card__school,
.tocu-stage-card__body,
.tocu-faq-card__body,
.tocu-resume-card__body {
  color: color-mix(in srgb, var(--tocu-ink) 72%, var(--tocu-muted) 28%);
  line-height: 1.68;
}

.tocu-home-links__body {
  grid-area: body;
  max-width: none;
  justify-self: start;
  align-self: start;
  font-size: 0.97rem;
  word-spacing: -0.05em;
}

.tocu-home-links__eyebrow {
  grid-area: eyebrow;
  color: color-mix(in srgb, var(--tocu-accent-strong) 70%, var(--tocu-subtle) 30%);
  align-self: start;
}

.tocu-home-links__arrow {
  grid-area: arrow;
  align-self: start;
  font-family: "Source Serif 4", "Noto Serif SC", serif;
  font-size: clamp(1.5rem, 2vw, 2rem);
  color: color-mix(in srgb, var(--tocu-ink) 46%, transparent);
}

.tocu-directory-toolbar {
  border: 0;
  background: transparent;
  padding: 0 0 0.85rem;
}

.tocu-directory-toolbar__filters {
  display: grid;
  grid-template-columns: minmax(0, 2.35fr) minmax(176px, 1fr);
  gap: 0.65rem;
  align-items: end;
  max-width: min(780px, 100%);
}

.tocu-field--search {
  margin: 0;
  min-width: 0;
}

.tocu-field--college {
  margin: 0;
  min-width: 0;
  max-width: none;
}

.tocu-field--college .tocu-field__label {
  margin-bottom: 0.25rem;
  font-size: 0.72rem;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: var(--tocu-subtle);
}

.tocu-directory-grid,
.tocu-stage-grid {
  display: grid;
  gap: 1rem;
}

.tocu-directory-grid {
  grid-template-columns: repeat(2, minmax(0, 1fr));
}

.tocu-directory-card {
  padding: 1.35rem;
  display: grid;
  gap: 1rem;
  border-radius: var(--tocu-radius-lg);
  border: 1px solid var(--tocu-border);
  background: rgba(255, 255, 255, 0.32);
  box-shadow: none;
  transition: transform var(--tocu-transition), border-color var(--tocu-transition), box-shadow var(--tocu-transition);
}

.tocu-directory-card__top {
  justify-content: space-between;
  align-items: start;
  gap: 1rem;
}

.tocu-program-title {
  display: flex;
  align-items: baseline;
  gap: 0.5rem;
  flex-wrap: wrap;
  margin: 0;
}

.tocu-program-title__en {
  font-family: "Noto Sans SC", "PingFang SC", "Microsoft YaHei", sans-serif;
  font-size: 0.9rem;
  font-weight: 500;
  color: var(--tocu-subtle);
}

.tocu-directory-card__school {
  margin: 0.35rem 0 0;
}

.tocu-directory-card__badge {
  color: var(--tocu-accent-strong);
  background: rgba(201, 100, 66, 0.08);
  border: 1px solid rgba(201, 100, 66, 0.16);
  border-radius: var(--tocu-radius-sm);
  padding: 0.45rem 0.7rem;
}

.tocu-directory-card__facts {
  display: grid;
  gap: 0.75rem;
  margin: 0;
}

.tocu-directory-card__facts div {
  display: grid;
  gap: 0.18rem;
}

.tocu-directory-card__facts dt {
  font-size: 0.78rem;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: var(--tocu-subtle);
}

.tocu-directory-card__facts dd {
  margin: 0;
  line-height: 1.7;
  color: var(--tocu-ink);
}

.tocu-directory-card__link,
.tocu-stage-card__cta {
  color: var(--tocu-accent-strong);
  font-weight: 600;
}

.tocu-resume-card {
  justify-content: space-between;
  gap: 1rem;
  padding: 1.2rem 1.35rem;
  background: rgba(255, 255, 255, 0.22);
}

.tocu-resume-card__title {
  margin-top: 0.4rem;
}

.tocu-stage-grid {
  grid-template-columns: repeat(3, minmax(0, 1fr));
}

.tocu-stage-card {
  padding: 1.35rem;
  border-radius: var(--tocu-radius-lg);
  border: 1px solid var(--tocu-border);
  background: rgba(255, 255, 255, 0.28);
  box-shadow: none;
  display: grid;
  gap: 0.9rem;
  transition: transform var(--tocu-transition), border-color var(--tocu-transition), box-shadow var(--tocu-transition);
}

.tocu-stage-card.is-highlighted {
  border-color: rgba(201, 100, 66, 0.26);
  background: rgba(255, 247, 243, 0.95);
  box-shadow: 0 0 0 1px rgba(201, 100, 66, 0.16);
}

.tocu-stage-card__meta {
  display: flex;
  justify-content: space-between;
  gap: 1rem;
  align-items: center;
  flex-wrap: wrap;
}

.tocu-stage-card__index {
  font-size: 0.75rem;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: var(--tocu-subtle);
}

.tocu-stage-card__range {
  font-size: 0.86rem;
  color: var(--tocu-accent-strong);
}

.tocu-guide-layout {
  display: grid;
  grid-template-columns: 250px minmax(0, 1fr) 260px;
  gap: 1rem;
  align-items: start;
}

.tocu-guide-nav,
.tocu-guide-side {
  position: sticky;
  top: 6.25rem;
}

.tocu-guide-nav__panel,
.tocu-guide-side__panel,
.tocu-guide-main__surface,
.tocu-faq-card,
.tocu-auth-modal {
  padding: 1.25rem;
}

.tocu-guide-nav__list,
.tocu-guide-side__materials,
.tocu-guide-main__section ol,
.tocu-guide-main__section ul {
  margin: 0;
  padding-left: 1.15rem;
}

.tocu-guide-nav__list {
  list-style: none;
  padding-left: 0;
  display: grid;
  gap: 0.55rem;
  margin-top: 1rem;
}

.tocu-guide-nav__link {
  display: flex;
  gap: 0.55rem;
  align-items: center;
  padding: 0.8rem 0.9rem;
  border-radius: var(--tocu-radius-md);
  border: 1px solid var(--tocu-border);
  color: var(--tocu-muted);
  transition: background-color var(--tocu-transition), color var(--tocu-transition), border-color var(--tocu-transition);
}

.tocu-guide-nav__link:hover {
  border-color: var(--tocu-border-strong);
  color: var(--tocu-ink);
}

.tocu-guide-nav__link.is-current {
  background: var(--tocu-ink);
  color: var(--tocu-surface);
  border-color: var(--tocu-ink);
}

.tocu-guide-main {
  display: grid;
  gap: 1rem;
}

.tocu-guide-main__heading {
  justify-content: space-between;
  gap: 1rem;
  align-items: start;
}

.tocu-guide-main__title {
  margin: 0.35rem 0 0;
  font-size: clamp(1.8rem, 3vw, 2.4rem);
  line-height: 1.18;
}

.tocu-guide-main__image {
  margin-top: 1.2rem;
  border-radius: var(--tocu-radius-lg);
  border: 1px solid var(--tocu-border);
  aspect-ratio: 16 / 9;
  object-fit: cover;
  background: var(--tocu-border-strong);
}

.tocu-guide-main__section {
  margin-top: 1.4rem;
}

.tocu-guide-main__section h3,
.tocu-guide-comments__title {
  margin: 0;
  font-family: "Source Serif 4", "Noto Serif SC", serif;
  font-size: 1.4rem;
  line-height: 1.2;
}

.tocu-guide-main__section ol,
.tocu-guide-main__section ul {
  margin-top: 0.9rem;
  color: var(--tocu-muted);
  line-height: 1.85;
}

.tocu-complete-button {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-height: 44px;
  padding: 0.75rem 1rem;
  border: 0;
  border-radius: var(--tocu-radius-md);
  background: #4F1C51;
  color: #fff;
  cursor: pointer;
  transition: transform var(--tocu-transition), opacity var(--tocu-transition);
}

.tocu-complete-button:hover {
  transform: translateY(-1px);
}

.tocu-guide-comments {
  margin-top: 1rem;
  display: grid;
  gap: 0.85rem;
}

.tocu-callout {
  margin-top: 0.8rem;
  border-radius: var(--tocu-radius-md);
  border: 1px solid rgba(201, 100, 66, 0.18);
  background: rgba(255, 247, 243, 0.92);
  color: var(--tocu-muted);
  padding: 0.95rem 1rem;
}

.tocu-callout a {
  color: var(--tocu-accent-strong);
}

.tocu-guide-side {
  display: grid;
  gap: 1rem;
}

.tocu-guide-side__panel--accent {
  background: linear-gradient(180deg, rgba(255, 247, 243, 0.98), rgba(250, 249, 245, 0.96));
  border-color: rgba(201, 100, 66, 0.18);
}

.tocu-guide-side__materials {
  margin-top: 0.9rem;
  display: grid;
  gap: 0.7rem;
  list-style: none;
  padding-left: 0;
}

.tocu-guide-side__materials li {
  padding: 0.8rem 0.9rem;
  border-radius: var(--tocu-radius-md);
  border: 1px solid var(--tocu-border);
  background: rgba(255, 255, 255, 0.7);
  color: var(--tocu-muted);
  line-height: 1.65;
}

.tocu-site-shell--assistant {
  width: min(1500px, calc(100% - 2rem));
  padding-top: 0.55rem;
  padding-bottom: 1.25rem;
}

body.tocu-body--assistant {
  background:
    radial-gradient(82% 70% at 50% 0%, rgba(201, 100, 66, 0.06), transparent 72%),
    radial-gradient(70% 55% at 0% 8%, rgba(255, 255, 255, 0.7), transparent 68%),
    var(--tocu-bg);
}

.tocu-site-header--assistant {
  border-bottom-color: rgba(232, 230, 220, 0.6);
  background: rgba(245, 244, 237, 0.76);
  backdrop-filter: blur(18px);
}

.tocu-site-header--assistant .tocu-site-nav {
  background: rgba(250, 249, 245, 0.64);
  border-color: rgba(232, 230, 220, 0.74);
  box-shadow: none;
}

.tocu-site-header--assistant .tocu-site-header__subtitle {
  color: color-mix(in srgb, var(--tocu-subtle) 82%, transparent);
}

.tocu-assistant-shell {
  position: relative;
  display: grid;
  min-height: calc(100svh - 7.4rem);
}

.tocu-assistant-shell__window {
  width: min(1240px, 100%);
  min-height: 100%;
  margin: 0 auto;
  display: grid;
  align-content: start;
  padding: clamp(1rem, 3vw, 2rem) clamp(0.2rem, 1vw, 0.4rem);
}

.tocu-assistant-shell__intro {
  width: min(1040px, 100%);
  margin: 0 auto;
  display: grid;
  justify-items: center;
  text-align: center;
  gap: 1.35rem;
  transition: opacity var(--tocu-transition), transform var(--tocu-transition), max-height var(--tocu-transition), margin var(--tocu-transition);
}

.tocu-assistant-shell__headline {
  margin: 0;
  font-family: "Source Serif 4", "Noto Serif SC", serif;
  font-size: clamp(2.9rem, 5vw, 4.5rem);
  font-weight: 600;
  line-height: 1.06;
  letter-spacing: -0.04em;
  color: var(--tocu-ink);
}

.tocu-assistant-shell__intro-copy {
  max-width: 34rem;
  margin: 0;
  font-size: 1rem;
  line-height: 1.8;
  color: var(--tocu-muted);
}

.tocu-chip-list {
  display: flex;
  flex-wrap: wrap;
  gap: 0.65rem;
}

.tocu-chip-list--assistant {
  justify-content: center;
  gap: 0.8rem 0.9rem;
  max-width: 92rem;
}

.tocu-chip {
  border: 1px solid rgba(232, 230, 220, 0.96);
  border-radius: var(--tocu-radius-md);
  background: rgba(255, 255, 255, 0.56);
  color: color-mix(in srgb, var(--tocu-ink) 82%, var(--tocu-muted) 18%);
  padding: 0.8rem 1.25rem;
  font-size: 1rem;
  line-height: 1.45;
  transition: border-color var(--tocu-transition), color var(--tocu-transition), background-color var(--tocu-transition), transform var(--tocu-transition);
  cursor: pointer;
}

.tocu-chip:hover {
  transform: translateY(-1px);
  border-color: rgba(201, 100, 66, 0.24);
  color: var(--tocu-ink);
  background: rgba(255, 255, 255, 0.76);
}

.tocu-chat-surface {
  width: min(940px, 100%);
  margin: 0 auto;
  max-height: 0;
  overflow: hidden;
  opacity: 0;
  pointer-events: none;
  transform: translateY(1.5rem);
  transition: opacity var(--tocu-transition), transform var(--tocu-transition);
}

.tocu-chat-log {
  min-height: calc(100svh - 16.5rem);
  max-height: calc(100svh - 16.5rem);
  overflow-y: auto;
  padding: 0 0 0.75rem;
  display: grid;
  gap: 1rem;
  background: transparent;
}

.tocu-chat-message {
  display: flex;
}

.tocu-chat-message--assistant {
  justify-content: flex-start;
}

.tocu-chat-message--user {
  justify-content: flex-end;
}

.tocu-chat-bubble {
  max-width: min(80%, 42rem);
  padding: 0.95rem 1.1rem;
  border-radius: var(--tocu-radius-lg);
  font-size: 0.98rem;
  line-height: 1.8;
  box-shadow: 0 10px 24px rgba(20, 20, 19, 0.04);
}

.tocu-chat-bubble--assistant {
  border: 1px solid rgba(232, 230, 220, 0.96);
  border-bottom-left-radius: 0.55rem;
  background: rgba(255, 255, 255, 0.84);
  color: var(--tocu-ink);
}

.tocu-chat-bubble--user {
  border-bottom-right-radius: 0.55rem;
  background: var(--tocu-accent);
  color: var(--tocu-surface);
}

.tocu-chat-bubble__text {
  margin: 0;
  white-space: pre-wrap;
}

.tocu-chat-bubble__meta-title,
.tocu-chat-bubble__timing {
  margin: 0.7rem 0 0;
  font-size: 0.74rem;
  color: color-mix(in srgb, var(--tocu-ink) 60%, var(--tocu-subtle) 40%);
}

.tocu-chat-bubble__sources {
  margin: 0.45rem 0 0;
  padding-left: 1rem;
  display: grid;
  gap: 0.2rem;
}

.tocu-chat-bubble__sources a {
  color: var(--tocu-accent-strong);
  font-size: 0.8rem;
}

.tocu-chat-bubble__sources a:hover {
  color: var(--tocu-accent);
}

.tocu-chat-compose {
  width: min(940px, calc(100% - 1rem));
}

.tocu-chat-compose--fixed {
  position: fixed;
  left: 50%;
  bottom: calc(1.1rem + env(safe-area-inset-bottom));
  transform: translateX(-50%);
  z-index: 32;
}

.tocu-chat-compose__status {
  margin: 0 0 0.45rem 0.3rem;
  color: var(--tocu-muted);
  font-size: 0.9rem;
}

.tocu-chat-compose__form {
  margin: 0;
}

.tocu-chat-compose__surface {
  display: grid;
  grid-template-columns: minmax(0, 1fr) auto;
  gap: 0.85rem;
  align-items: end;
  padding: 0.7rem 0.75rem 0.75rem 1.05rem;
  border-radius: var(--tocu-radius-lg);
  border: 1px solid rgba(196, 202, 255, 0.95);
  background: rgba(250, 249, 245, 0.98);
  box-shadow: 0 14px 36px rgba(146, 174, 255, 0.16);
}

.tocu-chat-compose__input {
  width: 100%;
  min-height: 4.8rem;
  max-height: 12rem;
  border: 0;
  background: transparent;
  color: var(--tocu-ink);
  resize: none;
  padding: 0.45rem 0 0;
  line-height: 1.7;
}

.tocu-chat-compose__input::placeholder {
  color: color-mix(in srgb, var(--tocu-subtle) 70%, transparent);
}

.tocu-chat-compose__input:focus {
  outline: none;
}

.tocu-chat-compose__send {
  width: 3.1rem;
  height: 3.1rem;
  border: 0;
  border-radius: var(--tocu-radius-round);
  display: grid;
  place-items: center;
  background: rgba(20, 20, 19, 0.08);
  color: var(--tocu-ink);
  font-size: 1.35rem;
  line-height: 1;
  cursor: pointer;
  transition: transform var(--tocu-transition), background-color var(--tocu-transition), color var(--tocu-transition);
}

.tocu-chat-compose__send:hover {
  transform: translateY(-1px);
  background: var(--tocu-accent);
  color: var(--tocu-surface);
}

.tocu-chat-compose__send:disabled {
  opacity: 0.72;
  cursor: not-allowed;
  transform: none;
}

.tocu-assistant-shell[data-assistant-stage="chat"] .tocu-assistant-shell__window {
  align-content: start;
}

.tocu-assistant-shell[data-assistant-stage="chat"] .tocu-assistant-shell__intro {
  opacity: 0;
  transform: translateY(-1.25rem);
  pointer-events: none;
  max-height: 0;
  overflow: hidden;
  margin-bottom: -1rem;
}

.tocu-assistant-shell[data-assistant-stage="chat"] .tocu-chat-surface {
  max-height: none;
  overflow: visible;
  opacity: 1;
  pointer-events: auto;
  transform: translateY(0);
}

.tocu-faq-list {
  display: grid;
  gap: 1rem;
}

.tocu-faq-card {
  display: grid;
  gap: 0.8rem;
}

.tocu-faq-card__badge {
  color: var(--tocu-accent-strong);
}

.tocu-auth-modal {
  width: min(560px, 100%);
  border-radius: var(--tocu-radius-lg);
  border: 1px solid var(--tocu-border);
  background: rgba(250, 249, 245, 0.98);
  box-shadow: 0 24px 44px rgba(20, 20, 19, 0.12);
}

.tocu-auth-modal__head {
  justify-content: space-between;
  gap: 1rem;
}

.tocu-auth-modal__tabs {
  gap: 0.5rem;
  margin-top: 1rem;
}

.tocu-auth-modal__tab {
  border-radius: var(--tocu-radius-sm);
  padding: 0.65rem 1rem;
}

.tocu-site-footer {
  border-top: 1px solid var(--tocu-border);
  margin-top: 2rem;
  padding: 1.4rem 0 2.5rem;
}

.tocu-site-footer__inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 1rem;
}

.tocu-site-footer__links {
  gap: 1rem;
  flex-wrap: wrap;
}

.tocu-site-footer__links a {
  color: var(--tocu-muted);
  font-size: 0.95rem;
}

.tocu-site-footer__links a:hover,
.tocu-breadcrumb a:hover {
  color: var(--tocu-ink);
}

/* 专业速查优化搜索栏样式 */
.tocu-optimized-searchbar {
  min-height: 4rem;
  width: 100%;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 1.5rem 0.5rem 1.5rem 0.5rem;
}
.tocu-optimized-searchbar__inner {
  width: 100%;
  max-width: 900px;
  display: flex;
  flex-direction: column;
  gap: 1rem;
}
@media (min-width: 640px) {
  .tocu-optimized-searchbar__inner {
    flex-direction: row;
    align-items: center;
  }
}
.tocu-optimized-searchbar__input-wrap {
  position: relative;
  flex: 1 1 0%;
  width: 100%;
}
.tocu-optimized-searchbar__icon {
  position: absolute;
  left: 0.75rem;
  top: 0;
  bottom: 0;
  display: flex;
  align-items: center;
  color: #bdbdbd;
  pointer-events: none;
}
.tocu-optimized-searchbar__input {
  width: 100%;
  padding-left: 2.5rem;
  padding-right: 2.5rem;
  padding-top: 0.85rem;
  padding-bottom: 0.85rem;
  background: #fff;
  border: 1px solid #e5e7eb;
  border-radius: 0.75rem;
  font-size: 1rem;
  transition: box-shadow 0.2s, border-color 0.2s;
  box-shadow: 0 1px 4px rgba(20,20,19,0.04);
}
.tocu-optimized-searchbar__input:focus {
  outline: none;
  border-color: #210F37;
  box-shadow: 0 0 0 2px #210F3733;
}
.tocu-optimized-searchbar__clear {
  position: absolute;
  right: 0.75rem;
  top: 0;
  bottom: 0;
  display: flex;
  align-items: center;
  background: none;
  border: none;
  color: #bdbdbd;
  cursor: pointer;
  padding: 0;
  transition: color 0.2s;
}
.tocu-optimized-searchbar__clear:hover {
  color: #666;
}
.tocu-optimized-searchbar__select-wrap {
  position: relative;
  width: 100%;
  max-width: 12rem;
  min-width: 8rem;
}
.tocu-optimized-searchbar__select {
  width: 100%;
  padding-left: 1.2rem;
  padding-right: 2.5rem;
  padding-top: 0.85rem;
  padding-bottom: 0.85rem;
  background: #fff;
  border: 1px solid #e5e7eb;
  border-radius: 0.75rem;
  font-size: 1rem;
  color: #444;
  appearance: none;
  box-shadow: 0 1px 4px rgba(20,20,19,0.04);
  cursor: pointer;
  transition: box-shadow 0.2s, border-color 0.2s;
}
.tocu-optimized-searchbar__select:focus {
  outline: none;
  border-color: #210F37;
  box-shadow: 0 0 0 2px #210F3733;
}
.tocu-optimized-searchbar__chevron {
  position: absolute;
  right: 0.75rem;
  top: 0;
  bottom: 0;
  display: flex;
  align-items: center;
  color: #bdbdbd;
  pointer-events: none;
}
.tocu-optimized-searchbar__btn {
  width: 100%;
  max-width: 8rem;
  padding: 0.85rem 2.5rem;
  background: #210F37;
  color: #fff;
  font-size: 1rem;
  font-weight: 500;
  border: none;
  border-radius: 0.75rem;
  box-shadow: 0 1px 4px rgba(20,20,19,0.04);
  cursor: pointer;
  transition: background 0.2s;
  white-space: nowrap;
}
.tocu-optimized-searchbar__btn:hover, .tocu-optimized-searchbar__btn:focus {
  background: #1a0a2a;
}
@media (min-width: 640px) {
  .tocu-optimized-searchbar__btn {
    width: auto;
  }
}
